@page "/settings"
@using sv_48b57f317c134e85870019537c5852a3.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Sidebar Navigation -->
    <nav class="settings-sidebar">
        <h4 class="sidebar-title">Settings</h4>
        @foreach (var section in _sections)
        {
            <button class="sidebar-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => SetActiveSection(section.Key)">
                <span class="sidebar-icon">@section.Value.Icon</span>
                <span>@section.Value.Label</span>
            </button>
        }
    </nav>

    <!-- Main Content -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5"><div class="spinner-border" role="status"></div></div>
        }
        else
        {
            <!-- Toast -->
            @if (_toastVisible)
            {
                <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                    @_toastMessage
                </div>
            }

            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

@* ── Profile ── *@
@{ RenderFragment RenderProfileSection() => __builder =>
{
    <section class="settings-section">
        <h3>Profile</h3>
        <p class="section-desc">Manage your personal information.</p>

        <div class="avatar-area">
            <img src="@_editProfile!.AvatarUrl" alt="Avatar" class="avatar-preview" />
            <span class="avatar-url">@_editProfile.AvatarUrl</span>
        </div>

        <div class="form-group">
            <label>Display Name</label>
            <input class="form-control" @bind="_editProfile.DisplayName" />
        </div>
        <div class="form-group">
            <label>Email</label>
            <input class="form-control" type="email" @bind="_editProfile.Email" />
        </div>
        <div class="form-group">
            <label>Bio</label>
            <textarea class="form-control" rows="4" @bind="_editProfile.Bio"></textarea>
        </div>

        <div class="btn-row">
            <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
        </div>
    </section>;
};}

@* ── Notifications ── *@
@{ RenderFragment RenderNotificationsSection() => __builder =>
{
    <section class="settings-section">
        <h3>Notifications</h3>
        <p class="section-desc">Control how you receive notifications.</p>

        <div class="toggle-row">
            <label class="toggle-label">Email Notifications</label>
            <label class="switch">
                <input type="checkbox" @bind="_editNotifications!.EmailNotifications" />
                <span class="slider"></span>
            </label>
        </div>
        <div class="toggle-row">
            <label class="toggle-label">Push Notifications</label>
            <label class="switch">
                <input type="checkbox" @bind="_editNotifications.PushNotifications" />
                <span class="slider"></span>
            </label>
        </div>
        <div class="toggle-row">
            <label class="toggle-label">Weekly Digest</label>
            <label class="switch">
                <input type="checkbox" @bind="_editNotifications.WeeklyDigest" />
                <span class="slider"></span>
            </label>
        </div>

        <h5 class="mt-4">Muted Channels</h5>
        <div class="channel-list">
            @foreach (var channel in _allChannels)
            {
                var isMuted = _editNotifications.MutedChannels.Contains(channel);
                <label class="channel-item">
                    <input type="checkbox" checked="@isMuted"
                           @onchange="e => ToggleMuteChannel(channel, (bool)e.Value!)" />
                    <span>#@channel</span>
                    <span class="badge @(isMuted ? "badge-muted" : "badge-active")">
                        @(isMuted ? "Muted" : "Active")
                    </span>
                </label>
            }
        </div>

        <div class="btn-row">
            <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Preferences")
            </button>
        </div>
    </section>;
};}

@* ── Security ── *@
@{ RenderFragment RenderSecuritySection() => __builder =>
{
    <section class="settings-section">
        <h3>Security</h3>
        <p class="section-desc">Manage passwords, 2FA, and active sessions.</p>

        <!-- Change Password -->
        <div class="expandable-panel">
            <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span>Change Password</span>
                <span class="chevron @(_passwordPanelOpen ? "open" : "")">▸</span>
            </button>
            @if (_passwordPanelOpen)
            {
                <div class="panel-body">
                    <div class="form-group">
                        <label>Current Password</label>
                        <input class="form-control" type="password" @bind="_currentPassword" />
                    </div>
                    <div class="form-group">
                        <label>New Password</label>
                        <input class="form-control" type="password" @bind="_newPassword" />
                    </div>
                    <div class="form-group">
                        <label>Confirm New Password</label>
                        <input class="form-control" type="password" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary" @onclick="ChangePassword" disabled="@_saving">
                        @(_saving ? "Updating…" : "Update Password")
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Auth -->
        <div class="toggle-row mt-4">
            <div>
                <label class="toggle-label">Two-Factor Authentication</label>
                <span class="status-indicator @(_security!.TwoFactorEnabled ? "status-on" : "status-off")">
                    @(_security.TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <label class="switch">
                <input type="checkbox" checked="@_security.TwoFactorEnabled" disabled />
                <span class="slider"></span>
            </label>
        </div>

        @if (_security.LastPasswordChange.HasValue)
        {
            <p class="text-muted small mt-2">
                Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }

        <!-- Active Sessions -->
        <h5 class="mt-4">Active Sessions</h5>
        <div class="table-responsive">
            <table class="table sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _security.Sessions)
                    {
                        var isCurrent = session.Id == _security.Sessions.FirstOrDefault()?.Id;
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (isCurrent)
                                {
                                    <span class="badge badge-current">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevokeSession(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop" @onclick="() => _sessionToRevoke = null">
                <div class="confirm-dialog" @onclick:stopPropagation>
                    <h5>Revoke Session</h5>
                    <p>
                        Are you sure you want to revoke the session on
                        <strong>@_sessionToRevoke.Device</strong> from
                        <strong>@_sessionToRevoke.Location</strong>?
                    </p>
                    <div class="btn-row">
                        <button class="btn btn-danger" @onclick="ConfirmRevokeSession" disabled="@_saving">
                            @(_saving ? "Revoking…" : "Revoke")
                        </button>
                        <button class="btn btn-outline-secondary" @onclick="() => _sessionToRevoke = null">Cancel</button>
                    </div>
                </div>
            </div>
        }
    </section>;
};}

@* ── Appearance ── *@
@{ RenderFragment RenderAppearanceSection() => __builder =>
{
    <section class="settings-section">
        <h3>Appearance</h3>
        <p class="section-desc">Customize the look and feel of the application.</p>

        <div class="form-group">
            <label class="fw-semibold">Theme</label>
            <div class="radio-group">
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <label class="radio-option">
                        <input type="radio" name="theme" value="@theme"
                               checked="@(_editAppearance!.Theme == theme)"
                               @onchange="() => _editAppearance.Theme = theme" />
                        <span>@theme</span>
                    </label>
                }
            </div>
        </div>

        <div class="form-group">
            <label class="fw-semibold">Font Size</label>
            <div class="radio-group">
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <label class="radio-option">
                        <input type="radio" name="fontSize" value="@size"
                               checked="@(_editAppearance!.FontSize == size)"
                               @onchange="() => _editAppearance.FontSize = size" />
                        <span>@size</span>
                    </label>
                }
            </div>
        </div>

        <div class="form-group">
            <label class="fw-semibold">Language</label>
            <select class="form-select" @bind="_editAppearance!.Language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <div class="toggle-row">
            <label class="toggle-label">Compact Mode</label>
            <label class="switch">
                <input type="checkbox" @bind="_editAppearance.CompactMode" />
                <span class="slider"></span>
            </label>
        </div>

        <!-- Live Preview -->
        <h5 class="mt-4">Live Preview</h5>
        <div class="preview-area @GetPreviewClasses()">
            <div class="preview-header">Dashboard</div>
            <p class="preview-body">
                This is a preview of your selected appearance settings.
                The theme, font size, and compact mode are reflected here.
            </p>
            <div class="preview-footer">
                <span class="preview-badge">Badge</span>
                <button class="preview-btn">Action</button>
            </div>
        </div>

        <div class="btn-row">
            <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>
    </section>;
};}

@code {
    // ── Section metadata ──
    private record SectionMeta(string Label, string Icon);

    private readonly Dictionary<string, SectionMeta> _sections = new()
    {
        ["profile"]       = new("Profile", "👤"),
        ["notifications"] = new("Notifications", "🔔"),
        ["security"]      = new("Security", "🔒"),
        ["appearance"]    = new("Appearance", "🎨"),
    };

    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;
    private bool _saving;

    // Toast
    private bool _toastVisible;
    private string _toastMessage = "";
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ── Profile state ──
    private UserProfile? _savedProfile;
    private ProfileEdit? _editProfile;

    // ── Notifications state ──
    private NotificationPrefs? _savedNotifications;
    private NotificationsEdit? _editNotifications;
    private readonly List<string> _allChannels = new() { "general", "random", "announcements", "dev-talk", "design" };

    // ── Security state ──
    private SecuritySettings? _security;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private ActiveSession? _sessionToRevoke;

    // ── Appearance state ──
    private AppearanceSettings? _savedAppearance;
    private AppearanceEdit? _editAppearance;
    private readonly string[] _languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese" };

    // ── Mutable edit models ──
    private class ProfileEdit
    {
        public string DisplayName { get; set; } = "";
        public string Email { get; set; } = "";
        public string AvatarUrl { get; set; } = "";
        public string Bio { get; set; } = "";

        public static ProfileEdit From(UserProfile p) =>
            new() { DisplayName = p.DisplayName, Email = p.Email, AvatarUrl = p.AvatarUrl, Bio = p.Bio };

        public UserProfile ToRecord() => new(DisplayName, Email, AvatarUrl, Bio);
    }

    private class NotificationsEdit
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public List<string> MutedChannels { get; set; } = new();

        public static NotificationsEdit From(NotificationPrefs p) =>
            new()
            {
                EmailNotifications = p.EmailNotifications,
                PushNotifications = p.PushNotifications,
                WeeklyDigest = p.WeeklyDigest,
                MutedChannels = new List<string>(p.MutedChannels),
            };

        public NotificationPrefs ToRecord() => new(EmailNotifications, PushNotifications, WeeklyDigest, new List<string>(MutedChannels));
    }

    private class AppearanceEdit
    {
        public string Theme { get; set; } = "Light";
        public string FontSize { get; set; } = "Medium";
        public string Language { get; set; } = "English";
        public bool CompactMode { get; set; }

        public static AppearanceEdit From(AppearanceSettings s) =>
            new() { Theme = s.Theme, FontSize = s.FontSize, Language = s.Language, CompactMode = s.CompactMode };

        public AppearanceSettings ToRecord() => new(Theme, FontSize, Language, CompactMode);
    }

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _savedProfile = profileTask.Result;
        _editProfile = ProfileEdit.From(_savedProfile);

        _savedNotifications = notifTask.Result;
        _editNotifications = NotificationsEdit.From(_savedNotifications);

        _security = securityTask.Result;

        _savedAppearance = appearanceTask.Result;
        _editAppearance = AppearanceEdit.From(_savedAppearance);

        _loading = false;
    }

    // ── Navigation ──

    private void SetActiveSection(string section) => ActiveSection = section;

    // ── Profile actions ──

    private async Task SaveProfile()
    {
        _saving = true;
        var record = _editProfile!.ToRecord();
        await SettingsService.SaveProfileAsync(record);
        _savedProfile = record;
        _saving = false;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        _editProfile = ProfileEdit.From(_savedProfile!);
        ShowToast("Changes discarded.", isError: false);
    }

    // ── Notifications actions ──

    private void ToggleMuteChannel(string channel, bool muted)
    {
        if (muted && !_editNotifications!.MutedChannels.Contains(channel))
            _editNotifications.MutedChannels.Add(channel);
        else if (!muted)
            _editNotifications!.MutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        var record = _editNotifications!.ToRecord();
        await SettingsService.SaveNotificationPrefsAsync(record);
        _savedNotifications = record;
        _saving = false;
        ShowToast("Notification preferences saved.");
    }

    // ── Security actions ──

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", isError: true);
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            ShowToast("New passwords do not match.", isError: true);
            return;
        }

        _saving = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = _newPassword = _confirmPassword = "";
        _passwordPanelOpen = false;
        _saving = false;
        ShowToast("Password updated successfully.");
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;
        _saving = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        _saving = false;
        ShowToast("Session revoked.");
    }

    // ── Appearance actions ──

    private string GetPreviewClasses()
    {
        var cls = $"preview-theme-{_editAppearance!.Theme.ToLowerInvariant()}";
        cls += $" preview-font-{_editAppearance.FontSize.ToLowerInvariant()}";
        if (_editAppearance.CompactMode) cls += " preview-compact";
        return cls;
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        var record = _editAppearance!.ToRecord();
        await SettingsService.SaveAppearanceAsync(record);
        _savedAppearance = record;
        _saving = false;
        ShowToast("Appearance settings saved.");
    }

    // ── Toast helper ──

    private void ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastMessage = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();

        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;
        _ = Task.Delay(3000, token).ContinueWith(_ =>
        {
            InvokeAsync(() => { _toastVisible = false; StateHasChanged(); });
        }, TaskContinuationOptions.NotOnCanceled);
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

