@page "/settings"
@using sv_48b57f317c134e85870019537c5852a3.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Sidebar Navigation -->
    <nav class="settings-sidebar">
        <h4 class="sidebar-title">Settings</h4>
        @foreach (var section in _sections)
        {
            <button class="sidebar-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => SetActiveSection(section.Key)">
                <span class="sidebar-icon">@section.Value.Icon</span>
                <span>@section.Value.Label</span>
            </button>
        }
    </nav>

    <!-- Main Content -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5"><div class="spinner-border" role="status"></div></div>
        }
        else
        {
            <!-- Toast -->
            @if (_toastVisible)
            {
                <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                    @_toastMessage
                </div>
            }

            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

@* ── Profile ── *@
@{ RenderFragment RenderProfileSection() => __builder =>
{
    <section class="settings-section">
        <h3>Profile</h3>
        <p class="section-desc">Manage your personal information.</p>

